<?xml version="1.0" encoding="UTF-8"?>
<file path="store/SalonContext.tsx">
  <content>
import React, { createContext, useContext, useState, useEffect } from 'react';
import { db } from '../firebaseConfig';
import {
    doc,
    onSnapshot,
    setDoc,
    DocumentReference,
    DocumentSnapshot
} from 'firebase/firestore';

interface TierLimit {
    [tierName: string]: number;
}

interface LoyaltyRule {
    id: string;
    minPoints: number;
    reward: string;
    active: boolean;
}

interface SystemConfig {
    tierLimits: TierLimit;
    loyaltyRules: LoyaltyRule[];
}

interface SalonContextType {
    systemConfig: SystemConfig | null;
    loading: boolean;
}

const defaultSystemConfig: SystemConfig = {
    tierLimits: {
        BRONZE: 0,
        SILVER: 5000,
        GOLD: 15000,
        PLATINUM: 30000,
        BLACK_VIP: 50000
    },
    loyaltyRules: [
        { id: 'lr1', minPoints: 10000, reward: 'Ücretsiz Yüz Maskesi Hediyesi!', active: true },
        { id: 'lr2', minPoints: 25000, reward: 'Vücut Analizi & Diyetisyen Randevusu Hediye!', active: true }
    ]
};

const SalonContext = createContext<SalonContextType>({
    systemConfig: null,
    loading: true,
});

export const useSalonContext = () => {
    return useContext(SalonContext);
};

export const SalonProvider: React.FC<{}> = ({ children }) => {
    const [systemConfig, setSystemConfig] = useState<SystemConfig | null>(null);
    const [loading, setLoading] = useState<boolean>(true);

    useEffect(() => {
        const systemConfigRef: DocumentReference = doc(db, 'system', 'config');

        const unsubscribe = onSnapshot(systemConfigRef, (docSnap: DocumentSnapshot) => {
            setLoading(true); // Reset loading state at the beginning of each snapshot

            if (docSnap.exists()) {
                const data = docSnap.data() as SystemConfig;
                setSystemConfig(data);
            } else {
                // If the document does not exist, set the default data
                setDoc(systemConfigRef, {
                    tierLimits: {
                        BRONZE: 0,
                        SILVER: 5000,
                        GOLD: 15000,
                        PLATINUM: 30000,
                        BLACK_VIP: 50000
                    },
                    loyaltyRules: [
                        { id: 'lr1', minPoints: 10000, reward: 'Ücretsiz Yüz Maskesi Hediyesi!', active: true },
                        { id: 'lr2', minPoints: 25000, reward: 'Vücut Analizi & Diyetisyen Randevusu Hediye!', active: true }
                    ]
                });
                setSystemConfig(defaultSystemConfig);
            }
            setLoading(false); // Set loading to false after data is loaded or defaults are applied
        }, (error) => {
            console.error("Error fetching system config:", error);
            setLoading(false); // Ensure loading is set to false in case of an error
        });

        return () => unsubscribe();
    }, []);

    const value: SalonContextType = {
        systemConfig,
        loading,
    };

    return (
        <SalonContext.Provider value={value}>
            {children}
        </SalonContext.Provider>
    );
};
  </content>
</file>
```

