  const searchCustomers = async (queryStr: string) => {
      if (isDemoMode) return; // Demo mode uses local filtering in component

      setIsLoadingCustomers(true);
      if (!queryStr) {
          // Reset to initial load if search is cleared
          const q = query(collection(db, 'customers'), limit(50));
          const snap = await getDocs(q);
          const loaded = snap.docs.map(d => ({...d.data(), id: d.id} as Customer)).filter(c => c.active !== false);
          setCustomers(loaded);
          setLastCustomerDoc(snap.docs[snap.docs.length - 1]);
          setHasMoreCustomers(snap.docs.length === 50);
      } else {
          // Server-side search (requires index on 'fullName')
          // Using a simple prefix search logic here.
          const q = query(
              collection(db, 'customers'), 
              where('fullName', '>=', queryStr),
              where('fullName', '<=', queryStr + '\uf8ff'),
              limit(50)
          );
          const snap = await getDocs(q);
          const loaded = snap.docs.map(d => ({...d.data(), id: d.id} as Customer)).filter(c => c.active !== false);
          setCustomers(loaded);
          // Search results generally don't support standard pagination easily without complex logic, 
          // so we disable 'load more' for search results in this simple implementation or implement a cursor based on search sort.
          setHasMoreCustomers(false); 
      }
      setIsLoadingCustomers(false);
  };

  const loadMoreCustomers = async () => {
      if (isDemoMode || !hasMoreCustomers || !lastCustomerDoc) return;

      setIsLoadingCustomers(true);
      const q = query(collection(db, 'customers'), startAfter(lastCustomerDoc), limit(50));
      const snap = await getDocs(q);

      if (!snap.empty) {
          const newCustomers = snap.docs.map(d => ({...d.data(), id: d.id} as Customer)).filter(c => c.active !== false);
          setCustomers(prev => [...prev, ...newCustomers]);
          setLastCustomerDoc(snap.docs[snap.docs.length - 1]);
          setHasMoreCustomers(snap.docs.length === 50);
      } else {
          setHasMoreCustomers(false);
      }
      setIsLoadingCustomers(false);
  };

